1	/**
2	 * Rig view aggregator — builds the UI-facing RigView from a persisted
3	 * RigDoc by joining against the Animator's per-session cost snapshot and
4	 * the Clerk writs book for the rig's writ title.
5	 *
6	 * Read-only. Pure derived fields; never persisted.
7	 *
8	 * Aggregation rules (see commission D17, D10):
9	 * - Every engine with a sessionId contributes to both the rig-level
10	 *   costSummary and the per-engine engineCosts map, regardless of engine
11	 *   status. Sessions that exist but haven't reported cost yet contribute
12	 *   zeros; sessions that are missing from the book are skipped silently.
13	 * - tokenUsage fields are optional: when no contributing session has
14	 *   tokenUsage, the aggregate inputTokens/outputTokens are omitted.
15	 * - writTitle is populated from the `clerk/writs` book via a direct book
16	 *   read. On a miss (book returns null/undefined), writTitle is left
17	 *   unset; the client renders an em-dash fallback for that one row.
18	 *
19	 * The cost data comes from AnimatorApi.getSessionCosts — the Animator owns
20	 * the shape of cost answers, so consumers like this aggregator do not reach
21	 * into the sessions book directly.
22	 */
23	
24	import { guild } from '@shardworks/nexus-core';
25	import type { AnimatorApi } from '@shardworks/animator-apparatus';
26	import type { StacksApi } from '@shardworks/stacks-apparatus';
27	import type { WritDoc } from '@shardworks/clerk-apparatus';
28	import type {
29	  RigDoc,
30	  RigView,
31	  RigCostSummary,
32	  EngineCostSummary,
33	} from './types.ts';
34	
35	/**
36	 * Build a RigView for a single rig by asking the Animator for cost/token
37	 * snapshots of every engine's session (if any) and summing across them.
38	 *
39	 * Does not mutate the rig. Safe to call on every read.
40	 *
41	 * Per-engine `sessionId` is read from the engine's latest attempt
42	 * (`attempts[-1].sessionId`) — the engine no longer carries a scalar
43	 * `sessionId` field. Earlier attempts' sessions (pre-retry) are not
44	 * currently aggregated; that is a deferred follow-up decision.
45	 */
46	export async function enrichRigView(rig: RigDoc): Promise<RigView> {
47	  // Look up the writ title from the clerk/writs book. Direct book read —
48	  // `book.get(id)` returns null/undefined on miss (no throw), matching the
49	  // omit-field semantic (client falls back to em-dash for that one row).
50	  const stacks = guild().apparatus<StacksApi>('stacks');
51	  const writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
52	  const writTitlePromise = rig.writId
53	    ? writsBook.get(rig.writId).then((w) => (w && typeof w.title === 'string' ? w.title : undefined))
54	    : Promise.resolve<string | undefined>(undefined);
55	
56	  // Collect (engineId, sessionId) pairs to look up.
57	  const pairs: Array<{ engineId: string; sessionId: string }> = [];
58	  for (const engine of rig.engines || []) {
59	    const attempts = engine.attempts ?? [];
60	    if (attempts.length === 0) continue;
61	    const tail = attempts[attempts.length - 1];
62	    if (tail.sessionId) {
63	      pairs.push({ engineId: engine.id, sessionId: tail.sessionId });
64	    }
65	  }
66	
67	  // No engines with sessions: no cost data to report — but still attach
68	  // the writ title if we resolved one.
69	  if (pairs.length === 0) {
70	    const writTitle = await writTitlePromise;
71	    const view: RigView = { ...rig };
72	    if (writTitle !== undefined) view.writTitle = writTitle;
73	    return view;
74	  }
75	
76	  // Resolve the Animator via the same apparatus-resolution mechanism
77	  // Spider's engines use elsewhere, and fetch cost snapshots in a single
78	  // bulk call. Missing ids are silently omitted from the returned Map
79	  // (see AnimatorApi.getSessionCosts), which preserves the "missing = zero
80	  // contribution" semantic this aggregator has always had.
81	  const animator = guild().apparatus<AnimatorApi>('animator');
82	  const [costs, writTitle] = await Promise.all([
83	    animator.getSessionCosts(pairs.map((p) => p.sessionId)),
84	    writTitlePromise,
85	  ]);
86	
87	  const engineCosts: Record<string, EngineCostSummary> = {};
88	  let totalCostUsd = 0;
89	  let totalInputTokens = 0;
90	  let totalOutputTokens = 0;
91	  let anyTokenUsage = false;
92	
93	  for (const { engineId, sessionId } of pairs) {
94	    const cost = costs.get(sessionId);
95	
96	    const costUsd = cost?.costUsd ?? 0;
97	    const inputTokens = cost?.inputTokens;
98	    const outputTokens = cost?.outputTokens;
99	
100	    const engineCost: EngineCostSummary = { costUsd };
101	    if (inputTokens !== undefined) engineCost.inputTokens = inputTokens;
102	    if (outputTokens !== undefined) engineCost.outputTokens = outputTokens;
103	    engineCosts[engineId] = engineCost;
104	
105	    totalCostUsd += costUsd;
106	    if (inputTokens !== undefined) {
107	      totalInputTokens += inputTokens;
108	      anyTokenUsage = true;
109	    }
110	    if (outputTokens !== undefined) {
111	      totalOutputTokens += outputTokens;
112	      anyTokenUsage = true;
113	    }
114	  }
115	
116	  const costSummary: RigCostSummary = { costUsd: totalCostUsd };
117	  if (anyTokenUsage) {
118	    costSummary.inputTokens = totalInputTokens;
119	    costSummary.outputTokens = totalOutputTokens;
120	  }
